// ═══════════════════════════════════════════════════════════════
//  核心战斗系统 — 数据类型定义
// ═══════════════════════════════════════════════════════════════

// ── 卡牌类型枚举 ──────────────────────────────────────────────
export enum CardType {
  PHYSICAL = '物理',
  MAGIC = '魔法',
  FUNCTION = '功能',
  DODGE = '闪避',
  ACTIVE = '主动',
  CURSE = '诅咒',
}

export type CardRarity = '普通' | '稀有';

// ── 伤害逻辑模式 ──────────────────────────────────────────────
/** 伤害计算模式 */
export type DamageMode = 'relative' | 'fixed' | 'mixed';

/**
 * 伤害逻辑定义
 * - relative: 伤害 = FinalPoint * scale + scaleAddition
 * - fixed:    伤害 = value（固定值，与点数无关）
 * - mixed:    伤害 = baseValue + FinalPoint * scale + scaleAddition
 */
export interface DamageLogic {
  mode: DamageMode;
  /** relative / mixed: 乘算系数，伤害 += FinalPoint * scale */
  scale?: number;
  /** relative / mixed: 加算值，伤害 += scaleAddition */
  scaleAddition?: number;
  /** fixed: 固定伤害值 */
  value?: number;
  /** mixed: 基础伤害值（与点数无关的底数） */
  baseValue?: number;
}

// ── 卡牌特性 ──────────────────────────────────────────────────
export type RerollTarget = 'self' | 'enemy' | 'none';

export interface CardTraits {
  /** 连击：打出后不消耗本回合常规行动次数 */
  combo: boolean;
  /** 首发连击：本场战斗第一次打出该卡牌时视为连击 */
  firstCombo?: boolean;
  /** 重掷目标 */
  reroll: RerollTarget;
  /** 过牌：配合连击实现快速过牌 */
  draw: boolean;
  /** 无法打出（通常用于诅咒卡）。 */
  unplayable?: boolean;
  /** 销毁：拼点胜利时，临时移除对方拼点失败的卡牌（仅本次战斗生效）。 */
  destroyOnClashWin?: boolean;
  /** 插入：卡牌生效后向对方牌库插入指定卡牌。 */
  insertCardsToEnemyDeck?: string[];
  /** 移除：打出后自我销毁（不进入弃牌堆）。 */
  purgeOnUse?: boolean;
}

// ── 卡牌点数计算参数 ──────────────────────────────────────────
export interface CardCalculation {
  /** 点数乘算系数，默认 1.0 */
  multiplier: number;
  /** 点数加算值，默认 0 */
  addition: number;
}

// ── 卡牌附带效果（打出时触发） ─────────────────────────────────

/** 效果数值来源 */
export type EffectValueMode = 'fixed' | 'point_scale' | 'max_hp_percent';
/** 卡牌附带效果触发时机 */
export type CardEffectTrigger =
  | 'on_use'
  | 'on_clash'
  | 'on_clash_fail'
  | 'on_dodge_success'
  | 'on_opponent_skip'
  | 'on_no_direct_damage_taken_this_turn'
  | 'on_turn_end_in_hand';

/** 卡牌打出时附带的效果 */
export interface CardEffect {
  /** 触发时机（默认 on_use） */
  triggers?: CardEffectTrigger[];

  /** 效果类别 */
  kind:
    | 'apply_buff'     // 为目标施加 Buff/Debuff
    | 'heal'           // 回复生命
    | 'damage'         // 造成伤害
    | 'restore_mana'   // 回复魔力
    | 'cleanse'        // 清除自身指定类型的 Debuff
    | 'modify_dice'    // 调整最小/最大骰子点数
    | 'escape';        // 触发逃离战斗

  // ── apply_buff 专用 ──
  /** 施加的效果类型（kind = apply_buff 时必填） */
  effectType?: EffectType;
  /** 目标：self = 使用者，enemy = 对方 */
  target?: 'self' | 'enemy';
  /** 束缚专用：限制的卡牌类型 */
  restrictedTypes?: CardType[];

  // ── 数值计算 ──
  /** 数值模式：fixed = 固定值，point_scale = FinalPoint * scale，max_hp_percent = 目标最大生命值 * scale */
  valueMode: EffectValueMode;
  /** fixed 模式下的固定值 */
  fixedValue?: number;
  /** point_scale / max_hp_percent 模式下的系数 */
  scale?: number;
  /** 持续回合数：仅对 apply_buff 生效，到回合结束时递减，归零后移除 */
  durationTurns?: number;
  /** damage 专用：是否视为真实伤害 */
  isTrueDamage?: boolean;
  /** damage 专用：是否计入直接伤害 */
  isDirectDamage?: boolean;

  // ── modify_dice 专用 ──
  /** 最小骰子点数加减值 */
  minDiceDelta?: number;
  /** 最大骰子点数加减值 */
  maxDiceDelta?: number;
  /** 最小骰子点数倍率 */
  minDiceMultiplier?: number;
  /** 最大骰子点数倍率 */
  maxDiceMultiplier?: number;

  // ── cleanse 专用 ──
  /** 要清除的 Debuff 类型列表（kind = cleanse 时使用，为空则清除全部） */
  cleanseTypes?: EffectType[];
}

export interface CardManaDrainConfig {
  /** fixed = 固定值；point_scale = FinalPoint * scale */
  mode: 'fixed' | 'point_scale';
  /** fixed 模式下的固定值 */
  value?: number;
  /** point_scale 模式下的系数 */
  scale?: number;
}

// ── 卡牌数据 ──────────────────────────────────────────────────
export interface CardData {
  id: string;
  name: string;
  type: CardType;
  /** 卡牌类别（大分类）：基础、敌人、火魔法、冰魔法等 */
  category: string;
  /** 稀有度 */
  rarity: CardRarity;
  /** 法力消耗（仅 Type == 魔法 时有效，其余为 0） */
  manaCost: number;
  /** 点数计算参数 */
  calculation: CardCalculation;
  /** 伤害逻辑 */
  damageLogic: DamageLogic;
  /** 攻击段数（仅攻击牌生效，默认1） */
  hitCount?: number;
  /** 特性开关 */
  traits: CardTraits;
  /** 打出时附带的效果列表（按顺序执行） */
  cardEffects: CardEffect[];
  /** 描述文本 */
  description: string;
  /** 负面效果：卡牌生效后记录到战斗后写入的 $负面状态（仅对玩家结算） */
  negativeEffect?: string;
  /** 法力汲取：卡牌生效后吸收对方对应数值法力并恢复自身；不足部分改为扣除对方生命 */
  manaDrain?: number | CardManaDrainConfig;
  /** 无视闪避：对闪避牌时不进入闪避拼点，直接生效 */
  ignoreDodge?: boolean;
  /** 群攻：对目标造成伤害时，永久减少其本场战斗中“群集/镜·群集”可恢复的生命值 */
  swarmAttack?: boolean;
  /** 逃离：任意一方打出后立刻结束战斗（无金币/卡牌奖励） */
  excape?: boolean;
  /**
   * 自伤：卡牌生效后对自己造成伤害（真实伤害或生命上限削减）
   * - number：固定生命伤害
   * - object：可配置固定/百分比 + 生命/生命上限
   */
  selfDamage?: number | CardSelfDamageConfig;
  /** 饕餮魔素：回合结束留在手中时，为自身施加侵蚀 */
  gluttonyEnchanted?: boolean;
  /** 卡牌图片（可选） */
  image?: string;
}

// ── 主动技能数据 ──────────────────────────────────────────────
export interface ActiveSkillData {
  id: string;
  name: string;
  type: CardType.ACTIVE;
  /** 主动技能类别（大分类）：基础、魔导等 */
  category: string;
  /** 稀有度 */
  rarity: CardRarity;
  /** 法力消耗 */
  manaCost: number;
  /** 冷却回合数 */
  Cooldown: number;
  /** 描述文本 */
  description: string;
  /** 使用条件描述（可选） */
  useCondition?: string;
  /** 单场战斗最大使用次数（可选） */
  maxUses?: number;
}

/** 自伤配置 */
export interface CardSelfDamageConfig {
  /** 数值（fixed=固定值；percent=百分比数值，例如 50 表示 50%） */
  value: number;
  /** fixed=固定值；percent=百分比 */
  mode?: 'fixed' | 'percent';
  /** hp=生命值；maxHp=生命上限 */
  target?: 'hp' | 'maxHp';
}

