/** 效果极性分类 */
export type EffectPolarity = 'buff' | 'debuff' | 'mixed' | 'trait' | 'special';

// ── 效果运行时实例 ────────────────────────────────────────────
export interface EffectInstance {
  type: EffectType;
  /** 当前层数 / 强度 */
  stacks: number;
  /** 效果极性 */
  polarity: EffectPolarity;
  /** 本回合新施加，标记后本回合不衰减（用于束缚/禁言/眩晕/被操控/流血等） */
  lockDecayThisTurn?: boolean;
  /**
   * 束缚特有：限制的卡牌类型列表
   * 例如 ['物理', '闪避'] 表示该束缚禁止使用物理和闪避牌
   */
  restrictedTypes?: CardType[];
  /** 效果来源标识（可选，调试/追溯用） */
  source?: string;
  /** 运行时计数（可选，供跨回合累计触发次数的效果使用） */
  runtimeCounter?: number;
  /** 剩余持续回合数（可选，回合结束时递减） */
  durationTurnsRemaining?: number;
}

// ── 游戏阶段枚举 ──────────────────────────────────────────────
export enum GamePhase {
  EXPLORE = 'EXPLORE',
  COMBAT = 'COMBAT',
}

// ── 战斗阶段枚举（状态机） ────────────────────────────────────
export enum CombatPhase {
  /** 回合开始：触发回合开始效果 */
  TURN_START = 'TURN_START',
  /** 抽牌阶段 */
  DRAW_PHASE = 'DRAW_PHASE',
  /** 敌人意图预告 */
  INTENT_PREVIEW = 'INTENT_PREVIEW',
  /** 玩家出牌输入 */
  PLAYER_INPUT = 'PLAYER_INPUT',
  /** 结算阶段 */
  RESOLUTION = 'RESOLUTION',
  /** 弃牌阶段 */
  DISCARD_PHASE = 'DISCARD_PHASE',
  /** 回合结束：触发回合结束效果 */
  TURN_END = 'TURN_END',
  /** 战斗胜利 */
  WIN = 'WIN',
  /** 战斗失败 */
  LOSE = 'LOSE',
}

// ── 实体属性 ──────────────────────────────────────────────────
export interface EntityStats {
  hp: number;
  maxHp: number;
  mp: number;
  /** 骰子范围 */
  minDice: number;
  maxDice: number;
  /** 本场战斗中“群集”可恢复生命值的累计削减量 */
  swarmHealReduction?: number;
  /** 当前身上的效果列表 */
  effects: EffectInstance[];
}

// ── 拼点结果 ──────────────────────────────────────────────────
export type ClashOutcome = 'player_win' | 'enemy_win' | 'draw' | 'dodge_success' | 'no_clash';

export interface ClashResult {
  outcome: ClashOutcome;
  playerFinalPoint: number;
  enemyFinalPoint: number;
  message: string;
}

// ── 战斗状态（完整运行时快照） ─────────────────────────────────
export interface CombatState {
  turn: number;
  phase: CombatPhase;
  /** 本回合剩余常规行动次数 */
  actionsRemaining: number;

  // 骰子
  playerBaseDice: number;
  enemyBaseDice: number;

  // 牌区
  playerHand: CardData[];
  playerDeck: CardData[];
  discardPile: CardData[];

  // 敌人
  enemyDeck: CardData[];
  enemyDiscard: CardData[];
  enemyIntentCard: CardData | null;
  enemyPredictedPoint: number;

  // 玩家选牌
  playerSelectedCard: CardData | null;

  // 上一张打出的牌（用于"复制上一张"等特殊效果）
  lastPlayedCard: CardData | null;

  // 战斗日志
  logs: string[];
}

// ── 圣遗物修正接口（框架预留） ────────────────────────────────
export interface RelicModifiers {
  /** 全局乘算 */
  globalMultiplier: number;
  /** 全局加算 */
  globalAddition: number;
}

// ── 点数计算上下文 ────────────────────────────────────────────
export interface PointCalculationContext {
  baseDice: number;
  card: CardData;
  entityEffects: EffectInstance[];
  relicModifiers: RelicModifiers;
}

// ── 伤害计算上下文 ────────────────────────────────────────────
export interface DamageCalculationContext {
  finalPoint: number;
  card: CardData;
  attackerEffects: EffectInstance[];
  defenderEffects: EffectInstance[];
  relicModifiers: RelicModifiers;
  /** 是否为真实伤害（无视防御） */
  isTrueDamage?: boolean;
}

// ── 敌人 AI 与定义 ────────────────────────────────────────────

/** 敌人 AI 决策上下文 — 提供完整战斗状态 */
export interface EnemyAIContext {
  /** 敌人自身属性（含 effects） */
  enemyStats: Readonly<EntityStats>;
  /** 玩家属性（含 effects） */
  playerStats: Readonly<EntityStats>;
  /** 当前可用牌 */
  deck: CardData[];
  /** 玩家当前手牌（最多传入3张用于读心类逻辑） */
  playerHand?: readonly CardData[];
  /** 玩家抽牌堆 */
  playerDeck?: readonly CardData[];
  /** 玩家弃牌堆 */
  playerDiscard?: readonly CardData[];
  /** 玩家上一回合实际打出的卡牌类型；跳过回合时为 null */
  previousPlayerCardType?: CardType | null;
  /** 当前回合数 */
  turn: number;
  /**
   * 自定义状态标记（各敌人自行使用）
   * 例如 { hasUsedHeal: false } 表示是否已使用过回复
   */
  flags: Record<string, any>;
}

/**
 * 敌人出牌选择函数
 * 每个敌人拥有完全独立的判定逻辑，
 * 可根据双方血量、蓝量、效果状态、回合数等任意条件决策。
 */
export type EnemyAISelectCard = (ctx: EnemyAIContext) => CardData;
export type EnemyAISelectTwinCards = (ctx: EnemyAIContext) => readonly [CardData, CardData];

/** 敌人定义 */
export interface EnemyDefinition {
  /** 敌人名称（注册表键） */
  name: string;
  /** 基础属性 */
  stats: EntityStats;
  /** 敌人的牌组 */
  deck: CardData[];
  /** 战败负面状态：若玩家败于该敌人，则在战斗结束后写入对应 $负面状态 */
  defeatNegativeStatus?: string | string[];
  /** 独立的出牌 AI 函数 */
  selectCard: EnemyAISelectCard;
  /** 双卡出牌 AI：若存在，则该敌人每回合会为不同位置选择两张牌 */
  selectTwinCards?: EnemyAISelectTwinCards;
}
